/**
 * Simulated database layer for the admin product catalog.
 * In a real app this would query your actual database or data access layer.
 */

const PRODUCTS = [
  { id: 1, sku: "LAP-001", name: "Laptop Pro",    price: 1299, inventory: 42, status: "active"   },
  { id: 2, sku: "PHN-002", name: "Phone X",       price: 799,  inventory: 18, status: "active"   },
  { id: 3, sku: "TAB-003", name: "Tablet Air",    price: 599,  inventory: 7,  status: "active"   },
  { id: 4, sku: "HDN-004", name: "Headphones",    price: 199,  inventory: 55, status: "active"   },
  { id: 5, sku: "WTH-005", name: "Watch Sport",   price: 349,  inventory: 23, status: "active"   },
  { id: 6, sku: "MON-006", name: "Monitor 27\"",  price: 449,  inventory: 0,  status: "inactive" },
  { id: 7, sku: "KBD-007", name: "Keyboard",      price: 129,  inventory: 31, status: "active"   },
  { id: 8, sku: "MSE-008", name: "Mouse",         price: 79,   inventory: 64, status: "active"   },
];

export async function getAllProducts() {
  // Simulate database query delay
  await new Promise((resolve) => setTimeout(resolve, 100));
  return PRODUCTS;
}

/**
 * Simulates a full catalog sync from an upstream ERP/PIM system.
 * In production this would fetch pricing, inventory, and availability
 * changes from the upstream source and update the database.
 */
export async function syncCatalog() {
  // Simulate the latency of a real upstream sync (a few seconds)
  await new Promise((resolve) => setTimeout(resolve, 3000));
  // In production: fetch and apply upstream changes here
  return { ok: true, message: "Catalog synced from upstream" };
}

/**
 * Returns a human-readable timestamp for the current time.
 */
export function getCurrentTimestamp() {
  return new Date().toISOString();
}

import { revalidateTag, redirect } from "next/cache";
import { cacheTag } from "next/cache";
import { getAllProducts, syncCatalog, getCurrentTimestamp } from "@/lib/db";
import type { ReactNode } from "react";

/* ───── Cached data fetching ───── */

async function getProducts() {
  "use cache";
  cacheTag("products");
  return getAllProducts();
}

/* ───── Types ───── */

type Product = {
  id: number;
  sku: string;
  name: string;
  price: number;
  inventory: number;
  status: string;
};

/* ───── Helpers ───── */

function formatPrice(price: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(price);
}

function StatusBadge({ status }: { status: string }) {
  const styles: Record<string, string> = {
    active: "badge badge--active",
    inactive: "badge badge--inactive",
  };
  return (
    <span className={styles[status] ?? "badge"}>{status}</span>
  );
}

/* ───── Page ───── */

export default async function AdminProductsPage({
  searchParams,
}: {
  searchParams: Promise<{ synced?: string }>;
}) {
  const { synced } = await searchParams;

  let products: Product[] = [];
  let error: string | null = null;

  try {
    products = await getProducts();
  } catch (e) {
    error = e instanceof Error ? e.message : "Failed to load products";
  }

  /* Inline Server Action — the sync trigger */
  async function syncAction() {
    "use server";

    // Kick off the upstream sync asynchronously so the admin
    // can continue working immediately (eventual consistency).
    syncCatalog().catch(() => {});

    // Invalidate every view that depends on this catalog data.
    revalidateTag("products");

    // Reload so the page reflects the triggered state.
    redirect("/admin/products?synced=true");
  }

  return (
    <div className="admin-catalog">
      <header className="admin-catalog__header">
        <h1 className="admin-catalog__title">Product Catalog</h1>

        <form action={syncAction} className="admin-catalog__sync-form">
          <button type="submit" className="btn btn--sync">
            Sync Latest Catalog
          </button>
        </form>
      </header>

      {synced === "true" && (
        <div className="alert alert--info" role="status">
          <strong>Sync triggered</strong> — catalog data will refresh
          in the background. Changes will appear across all catalog views
          within moments. Last triggered:{" "}
          <time dateTime={getCurrentTimestamp()}>
            {new Date(getCurrentTimestamp()).toLocaleTimeString()}
          </time>
        </div>
      )}

      {error && (
        <div className="alert alert--error" role="alert">
          <strong>Error loading products:</strong> {error}
        </div>
      )}

      {!error && products.length === 0 && (
        <div className="admin-catalog__empty" role="status">
          <p>The catalog is empty. Sync from your upstream ERP/PIM
          to populate products.</p>
        </div>
      )}

      {!error && products.length > 0 && (
        <div className="admin-catalog__table-wrapper">
          <table className="admin-catalog__table">
            <thead>
              <tr>
                <th>SKU</th>
                <th>Name</th>
                <th>Price</th>
                <th>Inventory</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {products.map((product) => (
                <tr key={product.id}>
                  <td className="cell-sku">{product.sku}</td>
                  <td className="cell-name">{product.name}</td>
                  <td className="cell-price">{formatPrice(product.price)}</td>
                  <td className={`cell-inventory ${
                    product.inventory === 0 ? "cell-inventory--empty" : ""
                  }`}>
                    {product.inventory}
                  </td>
                  <td>
                    <StatusBadge status={product.status} />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/*
        Styles are co-located for this exercise. In a real project
        you&apos;d pull these into a shared CSS module or design system.
      */}
      <style>{STYLES}</style>
    </div>
  );
}

/* ───── Co-located styles ───── */

const STYLES = `
  .admin-catalog {
    max-width: 960px;
    margin: 2rem auto;
    padding: 0 1rem;
    font-family: system-ui, -apple-system, sans-serif;
    color: #1a1a2e;
  }

  .admin-catalog__header {
    display: flex;
    align-items: center;
    justify-content: space-between;
