import { revalidateTag, cacheTag, cacheLife } from "next/cache";
import { redirect } from "next/navigation";
import { cookies } from "next/headers";
import { getAllProducts, syncCatalog } from "@/lib/db";

/* ───── Cached data fetching ───── */

async function getProducts() {
  "use cache";
  cacheLife("minutes");
  cacheTag("products");
  return getAllProducts();
}

/* ───── Helpers ───── */

function formatPrice(price: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(price);
}

function StatusBadge({ status }: { status: string }) {
  const styles: Record<string, string> = {
    active: "badge badge--active",
    inactive: "badge badge--inactive",
  };
  return (
    <span className={styles[status] ?? "badge"}>{status}</span>
  );
}

/* ───── Sync banner (needs dynamic cookies) ───── */

async function SyncBanner() {
  const cookieStore = await cookies();
  const syncedAt = cookieStore.get("admin_catalog_synced_at")?.value;

  if (!syncedAt) return null;

  return (
    <div className="alert alert--info" role="status">
      <strong>Sync triggered</strong> — catalog data will refresh
      in the background. Changes will appear across all catalog views
      within moments. Last triggered:{" "}
      <time dateTime={syncedAt}>
        {new Date(syncedAt).toLocaleTimeString()}
      </time>
    </div>
  );
}

/* ───── Products table (uses cached data) ───── */

async function ProductsTable() {
  let products: Array<{
    id: number;
    sku: string;
    name: string;
    price: number;
    inventory: number;
    status: string;
  }> = [];
  let error: string | null = null;

  try {
    products = await getProducts();
  } catch (e) {
    error = e instanceof Error ? e.message : "Failed to load products";
  }

  if (error) {
    return (
      <div className="alert alert--error" role="alert">
        <strong>Error loading products:</strong> {error}
      </div>
    );
  }

  if (products.length === 0) {
    return (
      <div className="admin-catalog__empty" role="status">
        <p>The catalog is empty. Sync from your upstream ERP/PIM
        to populate products.</p>
      </div>
    );
  }

  return (
    <div className="admin-catalog__table-wrapper">
      <table className="admin-catalog__table">
        <thead>
          <tr>
            <th>SKU</th>
            <th>Name</th>
            <th>Price</th>
            <th>Inventory</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td className="cell-sku">{product.sku}</td>
              <td className="cell-name">{product.name}</td>
              <td className="cell-price">{formatPrice(product.price)}</td>
              <td className={`cell-inventory ${
                product.inventory === 0 ? "cell-inventory--empty" : ""
              }`}>
                {product.inventory}
              </td>
              <td>
                <StatusBadge status={product.status} />
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ───── Server action (inline) ───── */

async function syncAction() {
  "use server";

  // Kick off the upstream sync asynchronously so the admin
  // can continue working immediately (eventual consistency).
  syncCatalog().catch(() => {});

  // Remember when the sync was triggered so the page can
  // display a confirmation banner after re-rendering.
  const cookieStore = await cookies();
  cookieStore.set("admin_catalog_synced_at", new Date().toISOString(), {
    path: "/admin/products",
    httpOnly: true,
    sameSite: "lax",
    maxAge: 60, // keep for 60 seconds — enough to show the banner on next render
  });

  // Invalidate every view that depends on this catalog data.
  revalidateTag("products", { expire: 0 });

  // Reload the page so the banner and fresh data are shown.
  redirect("/admin/products");
}

/* ───── Page ───── */

export default async function AdminProductsPage() {
  return (
    <div className="admin-catalog">
      <header className="admin-catalog__header">
        <h1 className="admin-catalog__title">Product Catalog</h1>

        <form action={syncAction} className="admin-catalog__sync-form">
          <button type="submit" className="btn btn--sync">
            Sync Latest Catalog
          </button>
        </form>
      </header>

      {/*
        SyncBanner reads cookies (dynamic), so it lives in Suspense
        to avoid blocking the rest of the page.
      */}
      <Suspense fallback={null}>
        <SyncBanner />
      </Suspense>

      {/*
        ProductsTable calls getProducts() which uses "use cache".
        The cache tag "products" means revalidateTag() in the
        server action invalidates it across all views.
      */}
      <ProductsTable />

      {/*
        Styles are co-located for this exercise. In a real project
        you'd pull these into a shared CSS module or design system.
      */}
      <style>{STYLES}</style>
    </div>
  );
}

